joi_block.script:
hold_ticks := 0
if ((#Plug #Office #Printer).plug_power < 5) {
hold_ticks = hold_ticks + 1
    if (hold_ticks >= 6000) {
(#Plug #Switch #Office #Printer).switch_off()
        break
}
}
else {
hold_ticks = 0
}

